import{_ as t,o as i,c as o,ag as r}from"./chunks/framework.DTiDeF2Q.js";const h=JSON.parse('{"title":"Alias Chmod | Dotfiles (IT)","titleTemplate":":title","description":"Semplifica la gestione dei permessi di file e directory con alias chmod. Scorciatoie rapide per pattern comuni come 755, 644 e altro.","frontmatter":{"title":"Alias Chmod | Dotfiles","description":"Semplifica la gestione dei permessi di file e directory con alias chmod. Scorciatoie rapide per pattern comuni come 755, 644 e altro.","lang":"it-IT","author":"Sebastien Rousseau","lastUpdated":true,"image":"/logo.png","imageAlt":"Alias Chmod preview","canonical":"/it/aliases/chmod/","robots":"index, follow","draft":false,"noindex":false,"sitemap":true,"breadcrumbTitle":"Alias Chmod","pageType":"docs","schemaType":"WebPage","metaTitle":"Alias Chmod - Dotfiles (IT)","permalink":"/it/aliases/chmod/","sidebar":true,"meta":[{"name":"keywords","content":"alias chmod, permessi file, scorciatoie shell, dotfiles, permessi unix"},{"name":"twitter:card","content":"summary"},{"name":"twitter:title","content":"Alias Chmod - Dotfiles"},{"name":"twitter:description","content":"Semplifica la gestione dei permessi di file e directory con alias chmod."},{"name":"og:title","content":"Alias Chmod - Dotfiles"},{"name":"og:description","content":"Semplifica la gestione dei permessi di file e directory con alias chmod."},{"name":"og:image:alt","content":"Dotfiles - Simply designed to fit your shell life"},{"name":"og:locale","content":"it_IT"}]},"headers":[],"relativePath":"it/aliases/chmod/index.md","filePath":"it/aliases/chmod/index.md","lastUpdated":1773010926000}'),a={name:"it/aliases/chmod/index.md"};function d(s,e,c,l,m,p){return i(),o("div",null,[...e[0]||(e[0]=[r('<h1 id="alias-chmod" tabindex="-1">Alias Chmod <a class="header-anchor" href="#alias-chmod" aria-label="Permalink to &quot;Alias Chmod&quot;">​</a></h1><p>Scorciatoie per gestire i permessi di file e directory.</p><h2 id="panoramica" tabindex="-1">Panoramica <a class="header-anchor" href="#panoramica" aria-label="Permalink to &quot;Panoramica&quot;">​</a></h2><p>Gli alias chmod forniscono un modo semplificato per gestire i permessi di file e directory dalla linea di comando. Invece di ricordare codici numerici, usa alias intuitivi come <code>chmod_755</code> o <code>chmod_u+x</code> per impostare rapidamente la modalita di accesso necessaria.</p><p>Questi alias sono definiti in <code>chmod.aliases.sh</code> e caricati automaticamente da chezmoi.</p><h2 id="riferimento" tabindex="-1">Riferimento <a class="header-anchor" href="#riferimento" aria-label="Permalink to &quot;Riferimento&quot;">​</a></h2><h3 id="alias-permessi-comuni" tabindex="-1">Alias permessi comuni <a class="header-anchor" href="#alias-permessi-comuni" aria-label="Permalink to &quot;Alias permessi comuni&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Alias</th><th>Permessi</th><th>Descrizione</th></tr></thead><tbody><tr><td><code>chmod_000</code></td><td><code>----------</code></td><td>Nessun permesso per nessuno</td></tr><tr><td><code>chmod_400</code></td><td><code>r--------</code></td><td>Solo lettura per il proprietario</td></tr><tr><td><code>chmod_444</code></td><td><code>r--r--r--</code></td><td>Solo lettura per tutti</td></tr><tr><td><code>chmod_600</code></td><td><code>rw-------</code></td><td>Lettura/scrittura per il proprietario</td></tr><tr><td><code>chmod_644</code></td><td><code>rw-r--r--</code></td><td>Lettura/scrittura proprietario, solo lettura altri</td></tr><tr><td><code>chmod_666</code></td><td><code>rw-rw-rw-</code></td><td>Lettura/scrittura per tutti</td></tr><tr><td><code>chmod_755</code></td><td><code>rwxr-xr-x</code></td><td>Completo proprietario, lettura/esecuzione altri</td></tr><tr><td><code>chmod_764</code></td><td><code>rwxrw-r--</code></td><td>Completo proprietario, lettura/scrittura gruppo</td></tr><tr><td><code>chmod_777</code></td><td><code>rwxrwxrwx</code></td><td>Permessi completi per tutti</td></tr></tbody></table><h3 id="alias-permessi-proprietario" tabindex="-1">Alias permessi proprietario <a class="header-anchor" href="#alias-permessi-proprietario" aria-label="Permalink to &quot;Alias permessi proprietario&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Alias</th><th>Descrizione</th></tr></thead><tbody><tr><td><code>chmod_u+x</code></td><td>Aggiungi permesso esecuzione al proprietario</td></tr><tr><td><code>chmod_u-x</code></td><td>Rimuovi permesso esecuzione al proprietario</td></tr><tr><td><code>chmod_u+w</code></td><td>Aggiungi permesso scrittura al proprietario</td></tr><tr><td><code>chmod_u-w</code></td><td>Rimuovi permesso scrittura al proprietario</td></tr><tr><td><code>chmod_u+r</code></td><td>Aggiungi permesso lettura al proprietario</td></tr><tr><td><code>chmod_u-r</code></td><td>Rimuovi permesso lettura al proprietario</td></tr></tbody></table><h3 id="alias-permessi-gruppo" tabindex="-1">Alias permessi gruppo <a class="header-anchor" href="#alias-permessi-gruppo" aria-label="Permalink to &quot;Alias permessi gruppo&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Alias</th><th>Descrizione</th></tr></thead><tbody><tr><td><code>chmod_g+x</code></td><td>Aggiungi permesso esecuzione al gruppo</td></tr><tr><td><code>chmod_g-x</code></td><td>Rimuovi permesso esecuzione al gruppo</td></tr><tr><td><code>chmod_g+w</code></td><td>Aggiungi permesso scrittura al gruppo</td></tr><tr><td><code>chmod_g-w</code></td><td>Rimuovi permesso scrittura al gruppo</td></tr><tr><td><code>chmod_g+r</code></td><td>Aggiungi permesso lettura al gruppo</td></tr><tr><td><code>chmod_g-r</code></td><td>Rimuovi permesso lettura al gruppo</td></tr></tbody></table><h3 id="alias-permessi-altri" tabindex="-1">Alias permessi altri <a class="header-anchor" href="#alias-permessi-altri" aria-label="Permalink to &quot;Alias permessi altri&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Alias</th><th>Descrizione</th></tr></thead><tbody><tr><td><code>chmod_o+x</code></td><td>Aggiungi permesso esecuzione agli altri</td></tr><tr><td><code>chmod_o-x</code></td><td>Rimuovi permesso esecuzione agli altri</td></tr><tr><td><code>chmod_o+w</code></td><td>Aggiungi permesso scrittura agli altri</td></tr><tr><td><code>chmod_o-w</code></td><td>Rimuovi permesso scrittura agli altri</td></tr><tr><td><code>chmod_o+r</code></td><td>Aggiungi permesso lettura agli altri</td></tr><tr><td><code>chmod_o-r</code></td><td>Rimuovi permesso lettura agli altri</td></tr></tbody></table><h3 id="alias-tipo-file" tabindex="-1">Alias tipo file <a class="header-anchor" href="#alias-tipo-file" aria-label="Permalink to &quot;Alias tipo file&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Alias</th><th>Descrizione</th></tr></thead><tbody><tr><td><code>chmod_755d</code></td><td>Imposta permessi directory a <code>rwxr-xr-x</code></td></tr><tr><td><code>chmod_644f</code></td><td>Imposta permessi file a <code>rw-r--r--</code></td></tr></tbody></table><h3 id="funzione-permessi-ricorsiva" tabindex="-1">Funzione permessi ricorsiva <a class="header-anchor" href="#funzione-permessi-ricorsiva" aria-label="Permalink to &quot;Funzione permessi ricorsiva&quot;">​</a></h3><p>La funzione <code>change_permission</code> applica permessi ricorsivamente con richiesta di conferma:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">change_permission</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 755</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /path/to/directory</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -R</span></span></code></pre></div>',19)])])}const u=t(a,[["render",d]]);export{h as __pageData,u as default};
